const listToolTickets = `-- name: ListToolTickets :many
SELECT
  tt.id,
  tt.post_id,
  tt.requested_by,
  tt.tool_name,
  tt.tool_description,
  tt.tool_website,
  tt.status,
  tt.resolved_tool_id,
  tt.resolved_by,
  tt.resolved_at,
  tt.created_at,
  tt.updated_at,
  p.name AS post_name,
  p.slug AS post_slug,
  requester.username AS requester_username,
  resolver.username AS resolver_username,
  COALESCE(
    jsonb_agg(
      DISTINCT jsonb_build_object(
        'id', c.id,
        'name', c.name
      )
    ) FILTER (WHERE c.id IS NOT NULL),
    '[]'::jsonb
  ) AS categories,
  COUNT(*) OVER() AS total_count
FROM
  tool_tickets tt
JOIN
  posts p ON tt.post_id = p.id
JOIN
  profiles requester ON tt.requested_by = requester.id
LEFT JOIN
  profiles resolver ON tt.resolved_by = resolver.id
LEFT JOIN
  tool_ticket_categories ttc ON tt.id = ttc.ticket_id
LEFT JOIN
  categories c ON ttc.category_id = c.id
WHERE
  ($1::text = '' OR tt.status = $1::text)
GROUP BY
  tt.id, p.name, p.slug, requester.username, resolver.username
ORDER BY
  tt.created_at DESC
LIMIT $2 OFFSET $3
`

