const renamePostWithSlugHistory = `-- name: RenamePostWithSlugHistory :exec
WITH old_post AS (
  SELECT p.id, p.slug, p.author_id
  FROM posts p
  WHERE p.id = $1 AND p.author_id = $2
),
post_update AS (
  UPDATE posts 
  SET name = $3, slug = $4, description = $5, updated_at = now()
  WHERE id = $1 AND author_id = $2
  RETURNING id, slug
),
history_insert AS (
  INSERT INTO post_slug_history (post_id, old_slug, current_slug)
  SELECT old_post.id, old_post.slug, post_update.slug
  FROM old_post, post_update
  WHERE old_post.slug != post_update.slug
  RETURNING post_id
)
UPDATE post_slug_history AS h
SET current_slug = $4
WHERE h.post_id = $1 AND h.current_slug != $4
`

type RenamePostWithSlugHistoryParams struct {
	PostID      uuid.UUID `json:"post_id"`
	AuthorID    uuid.UUID `json:"author_id"`
	Name        string    `json:"name"`
	CurrentSlug string    `json:"current_slug"`
	Description string    `json:"description"`
}

func (q *Queries) RenamePostWithSlugHistory(ctx context.Context, arg RenamePostWithSlugHistoryParams) error {
	_, err := q.db.Exec(ctx, renamePostWithSlugHistory,
		arg.PostID,
		arg.AuthorID,
		arg.Name,
		arg.CurrentSlug,
		arg.Description,
	)
	return err
}

