const searchPost = `-- name: SearchPost :many
SELECT 
  pwt.id, pwt.type, pwt.name, pwt.slug, pwt.description, pwt.updated_at, pwt.created_at, pwt.last_draft_update, pwt.last_publish, pwt.author_id, pwt.is_published, pwt.author_username, pwt.tools,
  ts_rank_cd((SELECT content_vector FROM posts WHERE id = pwt.id), websearch_to_tsquery('english', $1)) AS rank,
  COUNT(*) OVER() AS total_count,
  -- User status
  $4::boolean = true AND EXISTS(SELECT 1 FROM post_stars ps WHERE ps.post_id = pwt.id AND ps.liker_id = $5) AS is_starred
FROM posts_with_tools pwt
WHERE 
  websearch_to_tsquery('english', $1) @@ (SELECT content_vector FROM posts WHERE id = pwt.id) AND (($4::boolean = true AND pwt.author_id = $5) OR pwt.is_published)
ORDER BY 
  rank DESC
LIMIT $2 OFFSET $3
`

type SearchPostParams struct {
	WebsearchToTsquery string    `json:"websearch_to_tsquery"`
	Limit              int32     `json:"limit"`
	Offset             int32     `json:"offset"`
	IsAuthenticated    bool      `json:"is_authenticated"`
	AuthenticatedID    uuid.UUID `json:"authenticated_id"`
}

type SearchPostRow struct {
	ID              uuid.UUID          `json:"id"`
	Type            string             `json:"type"`
	Name            string             `json:"name"`
	Slug            string             `json:"slug"`
	Description     string             `json:"description"`
	UpdatedAt       pgtype.Timestamptz `json:"updated_at"`
	CreatedAt       pgtype.Timestamptz `json:"created_at"`
	LastDraftUpdate pgtype.Timestamptz `json:"last_draft_update"`
	LastPublish     pgtype.Timestamptz `json:"last_publish"`
	AuthorID        uuid.UUID          `json:"author_id"`
	IsPublished     pgtype.Bool        `json:"is_published"`
	AuthorUsername  string             `json:"author_username"`
	Tools           json.RawMessage    `json:"tools"`
	Rank            float32            `json:"rank"`
	TotalCount      int64              `json:"total_count"`
	IsStarred       pgtype.Bool        `json:"is_starred"`
}

func (q *Queries) SearchPost(ctx context.Context, arg SearchPostParams) ([]SearchPostRow, error) {
	rows, err := q.db.Query(ctx, searchPost,
		arg.WebsearchToTsquery,
		arg.Limit,
		arg.Offset,
		arg.IsAuthenticated,
		arg.AuthenticatedID,
	)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	var items []SearchPostRow
	for rows.Next() {
		var i SearchPostRow
		if err := rows.Scan(
			&i.ID,
			&i.Type,
			&i.Name,
			&i.Slug,
			&i.Description,
			&i.UpdatedAt,
			&i.CreatedAt,
			&i.LastDraftUpdate,
			&i.LastPublish,
			&i.AuthorID,
			&i.IsPublished,
			&i.AuthorUsername,
			&i.Tools,
			&i.Rank,
			&i.TotalCount,
			&i.IsStarred,
		); err != nil {
			return nil, err
		}
		items = append(items, i)
	}
	if err := rows.Err(); err != nil {
		return nil, err
	}
	return items, nil
}

